#!/bin/bash

# Setup script to create all portfolio source files automatically
# Run this from your my-portfolio directory: bash SETUP_SCRIPT.sh

echo "🚀 Setting up your portfolio structure..."

# Create directory structure
mkdir -p src/components src/styles

echo "Creating configuration files..."

# Create tsconfig.json
cat > tsconfig.json << 'EOF'
{
  "compilerOptions": {
      "target": "ES2020",
          "useDefineForClassFields": true,
              "lib": ["ES2020", "DOM", "DOM.Iterable"],
                  "module": "ESNext",
                      "skipLibCheck": true,
                          "esModuleInterop": true,
                              "allowSyntheticDefaultImports": true,
                                  "moduleResolution": "bundler",
                                      "allowImportingTsExtensions": true,
                                          "resolveJsonModule": true,
                                              "strict": true,
                                                  "noImplicitAny": true,
                                                      "strictNullChecks": true,
                                                          "strictFunctionTypes": true,
                                                              "strictBindCallApply": true,
                                                                  "strictPropertyInitialization": true,
                                                                      "noImplicitThis": true,
                                                                          "alwaysStrict": true,
                                                                              "noUnusedLocals": true,
                                                                                  "noUnusedParameters": true,
                                                                                      "noImplicitReturns": true,
                                                                                          "noFallthroughCasesInSwitch": true
                                                                                            },
                                                                                              "include": ["src"],
                                                                                                "references": [{ "path": "./tsconfig.node.json" }]
                                                                                                }
                                                                                                EOF

                                                                                                # Create tsconfig.node.json
                                                                                                cat > tsconfig.node.json << 'EOF'
                                                                                                {
                                                                                                  "compilerOptions": {
                                                                                                      "composite": true,
                                                                                                          "skipLibCheck": true,
                                                                                                              "module": "ESNext",
                                                                                                                  "moduleResolution": "bundler",
                                                                                                                      "allowSyntheticDefaultImports": true
                                                                                                                        },
                                                                                                                          "include": ["vite.config.ts"]
                                                                                                                          }
                                                                                                                          EOF
                                                                                                                          
                                                                                                                          # Create vite.config.ts
                                                                                                                          cat > vite.config.ts << 'EOF'
                                                                                                                          import { defineConfig } from 'vite'
                                                                                                                          import react from '@vitejs/plugin-react'
                                                                                                                          
                                                                                                                          export default defineConfig({
                                                                                                                            plugins: [react()],
                                                                                                                              server: {
                                                                                                                                  port: 5173,
                                                                                                                                      open: true,
                                                                                                                                          host: true
                                                                                                                                            },
                                                                                                                                              build: {
                                                                                                                                                  target: 'ES2020',
                                                                                                                                                      minify: 'terser',
                                                                                                                                                          sourcemap: false
                                                                                                                                                            }
                                                                                                                                                            })
                                                                                                                                                            EOF
                                                                                                                                                            
                                                                                                                                                            echo "Creating source files..."
                                                                                                                                                            
                                                                                                                                                            # Create src/vite-env.d.ts
                                                                                                                                                            cat > src/vite-env.d.ts << 'EOF'
                                                                                                                                                            /// <reference types="vite/client" />
                                                                                                                                                            EOF
                                                                                                                                                            
                                                                                                                                                            # Create src/main.tsx
                                                                                                                                                            cat > src/main.tsx << 'EOF'
                                                                                                                                                            import React from 'react'
                                                                                                                                                            import ReactDOM from 'react-dom/client'
                                                                                                                                                            import App from './App.tsx'
                                                                                                                                                            import './styles/App.css'
                                                                                                                                                            
                                                                                                                                                            ReactDOM.createRoot(document.getElementById('root')!).render(
                                                                                                                                                              <React.StrictMode>
                                                                                                                                                                  <App />
                                                                                                                                                                    </React.StrictMode>,
                                                                                                                                                                    )
                                                                                                                                                                    EOF
                                                                                                                                                                    
                                                                                                                                                                    # Create src/App.tsx
                                                                                                                                                                    cat > src/App.tsx << 'EOF'
                                                                                                                                                                    import React from 'react'
                                                                                                                                                                    import GoldenGate3D from './components/GoldenGate3D'
                                                                                                                                                                    import Hero from './components/Hero'
                                                                                                                                                                    import Portfolio from './components/Portfolio'
                                                                                                                                                                    import Skills from './components/Skills'
                                                                                                                                                                    import Contact from './components/Contact'
                                                                                                                                                                    import './styles/App.css'
                                                                                                                                                                    
                                                                                                                                                                    function App() {
                                                                                                                                                                      return (
                                                                                                                                                                          <div className="app-container">
                                                                                                                                                                                <GoldenGate3D />
                                                                                                                                                                                      <Hero />
                                                                                                                                                                                            <Portfolio />
                                                                                                                                                                                                  <Skills />
                                                                                                                                                                                                        <Contact />
                                                                                                                                                                                                            </div>
                                                                                                                                                                                                              )
                                                                                                                                                                                                              }
                                                                                                                                                                                                              
                                                                                                                                                                                                              export default App
                                                                                                                                                                                                              EOF
                                                                                                                                                                                                              
                                                                                                                                                                                                              echo "Creating components..."
                                                                                                                                                                                                              
                                                                                                                                                                                                              # Create GoldenGate3D.tsx
                                                                                                                                                                                                              cat > src/components/GoldenGate3D.tsx << 'EOF'
                                                                                                                                                                                                              import React, { useEffect, useRef } from 'react'
                                                                                                                                                                                                              import * as THREE from 'three'
                                                                                                                                                                                                              import gsap from 'gsap'
                                                                                                                                                                                                              
                                                                                                                                                                                                              const GoldenGate3D: React.FC = () => {
                                                                                                                                                                                                                const containerRef = useRef<HTMLDivElement>(null)
                                                                                                                                                                                                                
                                                                                                                                                                                                                  useEffect(() => {
                                                                                                                                                                                                                      if (!containerRef.current) return
                                                                                                                                                                                                                      
                                                                                                                                                                                                                          const scene = new THREE.Scene()
                                                                                                                                                                                                                              const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 10000)
                                                                                                                                                                                                                                  const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true })
                                                                                                                                                                                                                                      renderer.setSize(window.innerWidth, window.innerHeight)
                                                                                                                                                                                                                                          renderer.setClearColor(0x0a0e27, 1)
                                                                                                                                                                                                                                              containerRef.current.appendChild(renderer.domElement)
                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                  const sunLight = new THREE.DirectionalLight(0xff6b1a, 1.2)
                                                                                                                                                                                                                                                      sunLight.position.set(300, 200, 200)
                                                                                                                                                                                                                                                          scene.add(sunLight)
                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                              const ambientLight = new THREE.AmbientLight(0x404040, 0.8)
                                                                                                                                                                                                                                                                  scene.add(ambientLight)
                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                      const bridgeGroup = new THREE.Group()
                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                          // Cables
                                                                                                                                                                                                                                                                              const cableGeometry = new THREE.BufferGeometry()
                                                                                                                                                                                                                                                                                  const cablePoints = []
                                                                                                                                                                                                                                                                                      for (let i = 0; i <= 100; i++) {
                                                                                                                                                                                                                                                                                            const x = (i / 100) * 2000 - 1000
                                                                                                                                                                                                                                                                                                  const y = 300 + Math.sin((i / 100) * Math.PI) * 200
                                                                                                                                                                                                                                                                                                        const z = 0
                                                                                                                                                                                                                                                                                                              cablePoints.push(new THREE.Vector3(x, y, z))
                                                                                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                                                                                      cableGeometry.setFromPoints(cablePoints)
                                                                                                                                                                                                                                                                                                                          const cableMaterial = new THREE.LineBasicMaterial({ color: 0xff6b1a, linewidth: 3 })
                                                                                                                                                                                                                                                                                                                              const cables = new THREE.Line(cableGeometry, cableMaterial)
                                                                                                                                                                                                                                                                                                                                  bridgeGroup.add(cables)
                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                      // Deck
                                                                                                                                                                                                                                                                                                                                          const deckGeometry = new THREE.BoxGeometry(2000, 30, 100)
                                                                                                                                                                                                                                                                                                                                              const deckMaterial = new THREE.MeshStandardMaterial({ color: 0xff6b1a, metalness: 0.3, roughness: 0.4 })
                                                                                                                                                                                                                                                                                                                                                  const deck = new THREE.Mesh(deckGeometry, deckMaterial)
                                                                                                                                                                                                                                                                                                                                                      deck.position.y = -50
                                                                                                                                                                                                                                                                                                                                                          bridgeGroup.add(deck)
                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                              // Towers
                                                                                                                                                                                                                                                                                                                                                                  for (let x of [-500, 500]) {
                                                                                                                                                                                                                                                                                                                                                                        const towerGeometry = new THREE.BoxGeometry(50, 400, 50)
                                                                                                                                                                                                                                                                                                                                                                              const towerMaterial = new THREE.MeshStandardMaterial({ color: 0xff6b1a, metalness: 0.4, roughness: 0.3 })
                                                                                                                                                                                                                                                                                                                                                                                    const tower = new THREE.Mesh(towerGeometry, towerMaterial)
                                                                                                                                                                                                                                                                                                                                                                                          tower.position.set(x, 100, 0)
                                                                                                                                                                                                                                                                                                                                                                                                bridgeGroup.add(tower)
                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                        scene.add(bridgeGroup)
                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                            // Water
                                                                                                                                                                                                                                                                                                                                                                                                                const waterGeometry = new THREE.PlaneGeometry(4000, 3000)
                                                                                                                                                                                                                                                                                                                                                                                                                    const waterMaterial = new THREE.MeshStandardMaterial({ color: 0x1a4d6d, metalness: 0.5, roughness: 0.3 })
                                                                                                                                                                                                                                                                                                                                                                                                                        const water = new THREE.Mesh(waterGeometry, waterMaterial)
                                                                                                                                                                                                                                                                                                                                                                                                                            water.rotation.x = -Math.PI / 2
                                                                                                                                                                                                                                                                                                                                                                                                                                water.position.y = -400
                                                                                                                                                                                                                                                                                                                                                                                                                                    scene.add(water)
                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                        camera.position.set(0, 100, -1000)
                                                                                                                                                                                                                                                                                                                                                                                                                                            camera.lookAt(0, 100, 0)
                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                let animationId: number
                                                                                                                                                                                                                                                                                                                                                                                                                                                    const animate = () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                          animationId = requestAnimationFrame(animate)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                water.material.emissiveIntensity = 0.1 + Math.sin(Date.now() * 0.001) * 0.05
                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                      gsap.to(camera.position, {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                              z: 1000,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      duration: 25,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              repeat: -1,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      yoyo: true,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ease: 'sine.inOut'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          renderer.render(scene, camera)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  animate()
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const handleResize = () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            camera.aspect = window.innerWidth / window.innerHeight
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  camera.updateProjectionMatrix()
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        renderer.setSize(window.innerWidth, window.innerHeight)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                window.addEventListener('resize', handleResize)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          window.removeEventListener('resize', handleResize)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                cancelAnimationFrame(animationId)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      containerRef.current?.removeChild(renderer.domElement)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            renderer.dispose()
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }, [])
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return <div ref={containerRef} className="golden-gate-3d" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    export default GoldenGate3D
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    EOF
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    # Create Hero.tsx
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cat > src/components/Hero.tsx << 'EOF'
