                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        # Create Portfolio.tsx
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        cat > src/components/Portfolio.tsx << 'EOF'
